body.script:
document.addEventListener('DOMContentLoaded', () => {
  const display = document.getElementById('sandbox-display');
  const themeTag = document.getElementById('sandbox-theme-tag');
  const statusText = document.getElementById('sandbox-status-text');
  const logBox = document.getElementById('sandbox-log');
  const playBtn = document.getElementById('btn-sound-play');

  let activeSound = 'oof';

  // Web Audio API Synth to avoid downloading external files
  const audioCtx = new (window.AudioContext || window.webkitAudioContext)();

  function playSynthSound(type) {
    if (audioCtx.state === 'suspended') {
      audioCtx.resume();
    }

    const osc = audioCtx.createOscillator();
    const gain = audioCtx.createGain();

    osc.connect(gain);
    gain.connect(audioCtx.destination);

    const now = audioCtx.currentTime;

    if (type === 'oof') {
      // Classic Roblox "Oof" pitch modulation
      osc.type = 'sine';
      osc.frequency.setValueAtTime(130, now);
      osc.frequency.exponentialRampToValueAtTime(320, now + 0.15);

      gain.gain.setValueAtTime(0.5, now);
      gain.gain.exponentialRampToValueAtTime(0.01, now + 0.2);

      osc.start(now);
      osc.stop(now + 0.2);
    } else if (type === 'pew') {
      // Retro laser pew sound
      osc.type = 'sawtooth';
      osc.frequency.setValueAtTime(800, now);
      osc.frequency.exponentialRampToValueAtTime(80, now + 0.3);

      gain.gain.setValueAtTime(0.3, now);
      gain.gain.exponentialRampToValueAtTime(0.01, now + 0.3);

      osc.start(now);
      osc.stop(now + 0.3);
    } else if (type === 'coin') {
      // Mario coin sound (two quick high notes)
      osc.type = 'triangle';
      osc.frequency.setValueAtTime(987.77, now); // B5
      osc.frequency.setValueAtTime(1318.51, now + 0.08); // E6

      gain.gain.setValueAtTime(0.3, now);
      gain.gain.setValueAtTime(0.3, now + 0.08);
      gain.gain.exponentialRampToValueAtTime(0.01, now + 0.3);

      osc.start(now);
      osc.stop(now + 0.3);
    }
  }

  // Handler for Themes
  document.querySelectorAll('[data-action="theme"]').forEach(btn => {
    btn.addEventListener('click', () => {
      // Deactivate other theme buttons
      document.querySelectorAll('[data-action="theme"]').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');

      const theme = btn.getAttribute('data-value');
      display.className = 'preview-display'; // Reset
      display.classList.add(`theme-${theme}`);

      if (theme === 'classic') {
        themeTag.innerText = 'Theme: Default Dark';
        statusText.innerText = 'Dark themes loaded successfully.';
        logBox.innerText = '[SYS] Applied Registry dark theme values.';
        display.style.color = '#ffffff';
      } else if (theme === 'cyber') {
        themeTag.innerText = 'Theme: Cyberpunk Pink';
        statusText.innerText = 'Futuristic Cyberpunk UI initialized.';
        logBox.innerText = '[SYS] Loaded assets/custom_themes/cyberpink.json';
        display.style.color = '#ff007f';
      } else if (theme === 'white') {
        themeTag.innerText = 'Theme: Clean Light';
        statusText.innerText = 'Light mode override active.';
        logBox.innerText = '[SYS] Warning: Blinding light mode active.';
        display.style.color = '#0f172a';
      }
    });
  });

  // Handler for Sound Select
  document.querySelectorAll('[data-action="sound"]').forEach(btn => {
    btn.addEventListener('click', () => {
      document.querySelectorAll('[data-action="sound"]').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');

      activeSound = btn.getAttribute('data-value');
      statusText.innerText = `Selected Sound Pack: ${activeSound.toUpperCase()}`;
      logBox.innerText = `[SYS] Audio descriptor pointed to assets/sounds/${activeSound}.wav`;

      playSynthSound(activeSound);
    });
  });

  // Play Sound Action Trigger
  playBtn.addEventListener('click', (e) => {
    playSynthSound(activeSound);

    // Show visual ripple
    const ripple = document.createElement('div');
    ripple.classList.add('sound-ripple');
    display.appendChild(ripple);

    const rect = display.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    ripple.style.left = `${x - 10}px`;
    ripple.style.top = `${y - 10}px`;

    setTimeout(() => {
      ripple.remove();
    }, 600);
  });

});
